import type {Subscription} from "./common.d.ts";
import {FFmpeg} from "@ffmpeg/ffmpeg";

const baseURL = "./vendor/ffmpeg-core"

let coreURL: string | null = null
let coreFetchEvt: Subscription<string>[] | null = null
let wasmURL: string | null = null
let wasmFetchEvt: Subscription<string>[] | null = null

function getFileWithProgress(url: string, mime: string, progress: (ev: ProgressEvent) => void): Promise<string> {
    return new Promise((resolve, reject) => {
        const xhr = new XMLHttpRequest()
        xhr.onprogress = progress
        xhr.onload = ev => {
            const buf: Blob = xhr.response
            const typed = new Blob([buf], {type: mime})
            resolve(URL.createObjectURL(typed))
        }
        xhr.onerror = ev => {
            reject(ev)
        }
        xhr.open("GET", url, true)
        xhr.responseType = "blob"
        xhr.send()
    })
}

export async function getCore(progress: (ev: ProgressEvent) => void): Promise<string> {
    if (coreURL) return coreURL
    if (coreFetchEvt) return new Promise((resolve, reject) => coreFetchEvt!.push({
        resolve: resolve,
        reject: reject
    }))
    coreFetchEvt = []
    try {
        coreURL = await getFileWithProgress(`${baseURL}/ffmpeg-core.js`, 'text/javascript', progress)
        coreFetchEvt.forEach(it => it.resolve(coreURL!))
    } catch (e) {
        coreFetchEvt.forEach(it => it.reject(e))
        throw e
    } finally {
        coreFetchEvt = null
    }
    return coreURL
}

export async function getWasm(progress: (ev: ProgressEvent) => void): Promise<string> {
    if (wasmURL) return wasmURL
    if (wasmFetchEvt) return new Promise((resolve, reject) => wasmFetchEvt!.push({
        resolve: resolve,
        reject: reject
    }))
    wasmFetchEvt = []
    try {
        wasmURL = await getFileWithProgress(`${baseURL}/ffmpeg-core.wasm`, 'application/wasm', progress)
        wasmFetchEvt.forEach(it => it.resolve(wasmURL!))
    } catch (e) {
        wasmFetchEvt.forEach(it => it.reject(e))
        throw e
    } finally {
        wasmFetchEvt = null
    }
    return wasmURL
}

export async function newFFmpeg(preload: (ffmpeg: FFmpeg) => void): Promise<FFmpeg> {
    const ffmpeg = new FFmpeg()
    preload(ffmpeg)
    await ffmpeg.load({
        coreURL: await getCore(() => {
        }),
        wasmURL: await getWasm(() => {
        })
    })
    return ffmpeg
}

//@ts-ignore
window.newFFmpeg = newFFmpeg